using namespace std;

void traverseGraph(vector<vector<int>> adjMatrix, int startNode) {
    if (startNode < 0 || startNode >= adjMatrix.size()) {
        cout << "Error: Invalid starting node index." << endl;
        return;
    }

    if (adjMatrix.size() == 0 || adjMatrix[0].size() == 0) {
        cout << "Error: Empty graph." << endl;
        return;
    }

    vector<int> visited(adjMatrix.size(), false);
    queue<int> q;
    q.push(startNode);
    visited[startNode] = true;

    vector<int> order;

    while (!q.empty()) {
        int current = q.front();
        q.pop();
        order.push_back(current);

        for (int neighbor : adjMatrix[current]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }

    cout << "Order of nodes visited: ";
    for (int node : order) {
        cout << node << " ";
    }
    cout << endl;
}

// Example usage
int main() {
    vector<vector<int>> adjMatrix = {
        {0, 1, 2},
        {1, 0, 3},
        {2, 3, 0}
    };

    int startNode = 0;
    traverseGraph(adjMatrix, startNode);
    return 0;
}

