Node* processLinkedList(Node* head) {
    if (head == nullptr) {
        // Handle empty list case
        return nullptr;
    }

    Node* current = head;
    int position = 1;

    // Traverse the list and modify values
    while (current != nullptr) {
        current->value *= position;
        position++;
        current = current->next;
    }

    return head;
