use std::collections::{HashSet, VecDeque};

pub fn find_path(graph: &Graph, start: &str, end: &str, use_dfs: bool) -> Result<String, String> {
    if !graph.contains_node(start) || !graph.contains_node(end) {
        return Err(format!("Nodes {} or {} not found in the graph.", start, end));
    }

    let mut visited = HashSet::new();
    let mut path = Vec::new();
    let mut queue = VecDeque::new();

    if start == end {
        return Ok(format!("Path: {}", start));
    }

    if use_dfs {
        dfs(graph, start, end, &mut visited, &mut path, &mut queue);
    } else {
        bfs(graph, start, end, &mut visited, &mut path);
    }

    if path.len() == 0 {
        return Err("No path found between start and end nodes.".to_string());
    }

    Ok(format!("Path: {}", path.join(" -> ")))
}

fn dfs<'a, 'b>(graph: &'a Graph, start: &str, end: &str, visited: &mut HashSet<String>, path: &mut Vec<String>, queue: &mut VecDeque<String>) {
    visited.insert(start.to_string());
    path.push(start.to_string());

    if start == end {
        return;
    }

    for neighbor in graph.get_neighbors(start).unwrap_or(&[]) {
        if !visited.contains(neighbor) {
            dfs(graph, neighbor, end, visited, path, queue);
            if path.len() > 1 {
                path.pop();
            }
        }
    }

    path.pop();
}

fn bfs<'a, 'b>(graph: &'a Graph, start: &str, end: &str, visited: &mut HashSet<String>, path: &mut Vec<String>) {
    visited.insert(start.to_string());
    path.push(start.to_string());

    let mut queue = VecDeque::new();
    queue.push_back(start.to_string());

    while let Some(node) = queue.pop_front() {
        if node == end {
            break;
        }

        for neighbor in graph.get_neighbors(&node).unwrap_or(&[]) {
            if !visited.contains(neighbor) {
                visited.insert(neighbor.to_string());
                path.push(neighbor.to_string());
                queue.push_back(neighbor.to_string());
            }
        }
    }
