int findShortestPath(int start, int end, vector<vector<Edge>>& graph) {
    if (start < 0 || start >= graph.size() || end < 0 || end >= graph.size()) {
        return -1; // Invalid nodes
    }

    int numNodes = graph.size();
    vector<int> dist(numNodes, INT_MAX);
    dist[start] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    pq.push({0, start});

    while (!pq.empty()) {
        int currentDist = pq.top().first;
        int currentNode = pq.top().second;
        pq.pop();

        if (currentNode == end) {
            break;
        }

        if (currentDist > dist[currentNode]) {
            continue;
        }

        for (Edge edge : graph[currentNode]) {
            int neighbor = edge.to;
            int weight = edge.weight;
            if (dist[neighbor] > dist[currentNode] + weight) {
                dist[neighbor] = dist[currentNode] + weight;
                pq.push({dist[neighbor], neighbor});
            }
        }
    }

    return dist[end];
}

