import heapq

def shortest_path_distances(graph, start, algorithm='dijkstra'):
    if algorithm == 'dijkstra':
        dist = {node: float('inf') for node in graph}
        dist[start] = 0
        priority_queue = [(0, start)]
        visited = set()

        while priority_queue:
            current_dist, current_node = heapq.heappop(priority_queue)
            if current_node in visited:
                continue
            visited.add(current_node)
            for neighbor, weight in graph[current_node].items():
                if dist[neighbor] > dist[current_node] + weight:
                    dist[neighbor] = dist[current_node] + weight
                    heapq.heappush(priority_queue, (dist[neighbor], neighbor))
        return dist
    elif algorithm == 'bellman-ford':
        dist = {node: float('inf') for node in graph}
        dist[start] = 0
        for _ in range(max(len(graph) - 1, 0)):
            updated = False
            for node in graph:
                for neighbor, weight in graph[node].items():
                    if dist[neighbor] > dist[node] + weight:
                        dist[neighbor] = dist[node] + weight
                        updated = True
            if not updated:
                break
        return dist
    else:
        raise ValueError("Invalid algorithm specified. Use 'dijkstra' or 'bellman-ford'.")
