                continue
            if i == 0 or i == rows - 1 or j == 0 or j == cols - 1:
                continue
            # Check if current cell is lower than its neighbors
            if matrix[i][j] < matrix[i-1][j] and matrix[i][j] < matrix[i+1][j] and matrix[i][j] < matrix[i][j-1] and matrix[i][j] < matrix[i][j+1]:
