void computeShortestPathFromNode(std::vector<std::vector<int>> adjacencyMatrix, int startNode) {
    if (startNode < 0 || startNode >= adjacencyMatrix.size()) {
        throw std::out_of_range("Start node index is out of bounds");
    }

    int n = adjacencyMatrix.size();
    std::vector<int> dist(n, -1);
    std::vector<bool> visited(n, false);

    dist[startNode] = 0;
    visited[startNode] = true;

    for (int i = 0; i < n; ++i) {
        int minDist = -1;
        int minIndex = -1;

        for (int j = 0; j < n; ++j) {
            if (visited[j] && dist[j] != -1 && (minDist == -1 || dist[j] < minDist)) {
                minDist = dist[j];
                minIndex = j;
            }
        }

        if (minIndex == -1) {
            break;
        }

        visited[minIndex] = true;
        for (int j = 0; j < n; ++j) {
            if (!visited[j] && adjacencyMatrix[minIndex][j] > 0) {
                dist[j] = dist[minIndex] + 1;
            }
        }
    }

    // Output the shortest path
    std::vector<int> path;
    int current = startNode;
    while (current != -1) {
        path.push_back(current);
        current = dist[current];
    }

    // Reverse the path
    std::reverse(path.begin(), path.end());

    // Print the path
    for (int i = 0; i < path.size(); ++i) {
        std::cout << path[i] << " ";
    }
    std::cout << std::endl;
}

